window.chineseSwitcher={originalContent:null,converter:null,init:function(){this.loadOpenCC().then(()=>{this.initSwitcher()})},loadOpenCC:function(){return new Promise(e=>{if(window.OpenCC){this.converter=OpenCC.Converter({from:"tw",to:"cn"}),e();return}const t=document.createElement("script");t.src="/js/opencc-js-1.0.5/opencc.js",t.onload=()=>{this.converter=OpenCC.Converter({from:"tw",to:"cn"}),e()},document.head.appendChild(t)})},initSwitcher:function(){const t=document.querySelector("article");if(!t)return;this.originalContent=t.innerHTML;const n=document.querySelector('[data-lang="zh-tw"]'),e=document.querySelector('[data-lang="zh-cn"]');if(!n||!e)return;e.addEventListener("click",()=>{if(e.classList.contains("active"))return;e.classList.add("active"),n.classList.remove("active"),t.innerHTML===this.originalContent&&(t.innerHTML=this.converter(this.originalContent)),localStorage.setItem("preferredChinese","cn")}),n.addEventListener("click",()=>{if(n.classList.contains("active"))return;n.classList.add("active"),e.classList.remove("active"),this.originalContent&&(t.innerHTML=this.originalContent),localStorage.setItem("preferredChinese","tw")});const s=localStorage.getItem("preferredChinese");s==="cn"&&e.click(),console.log("繁簡切換初始化完成")}}